#include <bits/stdc++.h>
using namespace std;
int main(){
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    vector<vector<int>> g(n + 1);
    for (int i = 0; i < n - 1; i++) { int u, v; cin >> u >> v; g[u].push_back(v); g[v].push_back(u); }
    auto bfs = [&](int s){
        vector<int> d(n + 1, -1); d[s] = 0;
        queue<int> q; q.push(s);
        int far = s;
        while (!q.empty()) { int u = q.front(); q.pop(); if (d[u] > d[far]) far = u; for (int v : g[u]) if (d[v] == -1) { d[v] = d[u] + 1; q.push(v); } }
        return make_pair(far, d[far]);
    };
    auto [a, _] = bfs(1);
    auto [b, dist] = bfs(a);
    cout << dist << '\n';
}
